p.is_deleted = '0'
AND p.material_id IS NOT NULL
AND p.material_id != ''

    AND p.production_order_no LIKE CONCAT('%', #{req.productionOrderNoLike}, '%')


    AND (p.product_materiel LIKE CONCAT('%', #{req.productLike}, '%')
         OR p.product_name LIKE CONCAT('%', #{req.productLike}, '%')
         OR p.product_serial_no LIKE CONCAT('%', #{req.productLike}, '%'))


    AND (p.material_code LIKE CONCAT('%', #{req.materialLike}, '%')
         OR p.material_name LIKE CONCAT('%', #{req.materialLike}, '%'))


    AND p.delivery_status = #{req.deliveryStatus}


    AND p.inbound_status = #{req.inboundStatus}


    AND p.outbound_status = #{req.outboundStatus}


    AND p.material_source = #{req.materialSource}


    AND p.requirement_date >= #{req.requirementDateBegin}


    AND p.requirement_date <= #{req.requirementDateEnd}
